#!/bin/bash
#SBATCH --job-name=diffdock_eval_pb_failed
#SBATCH --account=MPHIL-DIS-SL2-GPU
#SBATCH --partition=ampere
#SBATCH --nodes=1
#SBATCH --ntasks=1
#SBATCH --cpus-per-task=4
#SBATCH --gres=gpu:1
#SBATCH --mem=32G
#SBATCH --time=12:00:00
#SBATCH --output=/home/qf226/MProject/DiffDock/logs/diffdock_eval_pb_failed_%j.out
#SBATCH --error=/home/qf226/MProject/DiffDock/logs/diffdock_eval_pb_failed_%j.err

# Evaluate the 27 posebusters complexes skipped by the parallel run due to
# tensor size mismatches from modified residues. Uses embeddings generated by
# diffdock_failed_esm.sh via ProDy-based sequence extraction (same as graph
# construction) so receptor feature dimensions match.

DIFFDOCK_DIR=/home/qf226/MProject/DiffDock
RDS=/home/qf226/rds/hpc-work/data

source ~/.bashrc
conda activate diffdock
export LD_LIBRARY_PATH="$CONDA_PREFIX/lib:$LD_LIBRARY_PATH"
export PYTHONPATH="$DIFFDOCK_DIR:$PYTHONPATH"

RDS_RESULTS=/home/qf226/rds/hpc-work/results

cd "$DIFFDOCK_DIR"
mkdir -p logs "$RDS_RESULTS/pb_evaluate_v2/chunk_failed"

python evaluate.py \
    --config default_inference_args.yaml \
    --dataset posebusters \
    --data_dir $RDS/posebusters_benchmark_set \
    --split_path data/splits/pb_failed_eval.txt \
    --cache_path $RDS/cache_pb_rebuild_torsion \
    --out_dir "$RDS_RESULTS/pb_evaluate_v2/chunk_failed" \
    --samples_per_complex 40 \
    --batch_size 40 \
    --chain_cutoff 10 \
    --protein_file protein \
    --ligand_file ligands \
    --esm_embeddings_path $RDS/embeddings/posebusters_esm2_failed.pt \
    --save_predictions \
    --num_workers 4
